// Slice 0 / Fase C (v2) - lee el raw body desde BINARIO ('data'), no desde $json.rawBody.
// En esta version de n8n, el Webhook con "Raw Body" ON entrega el cuerpo crudo como
// binario (item.binary.data), no como rawBody. getBinaryDataBuffer da los bytes exactos.
const crypto = require('crypto');

// Secreto: prioridad Variables ($vars); fallback in-node (sanitizado en el template).
const SECRET = (typeof $vars !== 'undefined' && $vars && $vars.VITA_HMAC_SECRET)
  ? $vars.VITA_HMAC_SECRET
  : '__PEGAR_SECRETO_O_USAR_VARIABLE__';

// Assert duro (L-C-08): si el secreto no esta en Variables, abortar; no operar con placeholder.
if (!SECRET || SECRET === '__PEGAR_SECRETO_O_USAR_VARIABLE__') {
  throw new Error('VITA_HMAC_SECRET no configurado en n8n Variables; abortando (assert duro).');
}

const item = $input.first();
const wh = item.json;

// 1) Raw body como Buffer EXACTO. Prioridad: binario 'data'. Fallback: wh.rawBody.
let buf = null;
try {
  if (item.binary && item.binary.data) {
    buf = await this.helpers.getBinaryDataBuffer(0, 'data');
  }
} catch (e) {
  buf = null;
}
if (!buf) {
  const rawField = wh.rawBody;
  if (Buffer.isBuffer(rawField)) buf = rawField;
  else if (rawField && rawField.type === 'Buffer' && Array.isArray(rawField.data)) buf = Buffer.from(rawField.data);
  else if (typeof rawField === 'string') buf = Buffer.from(rawField, 'utf8');
}
if (!buf) {
  return [{ json: { ok_firma: false, motivo: 'raw_body_ausente', ambiente_esperado: null, rol: null, action: null, ts: null } }];
}

// 2) Firma recibida en el header.
const headers = wh.headers || {};
const sigHeader = headers['x-vita-signature'] || headers['X-Vita-Signature'] || '';

// 3) HMAC recomputado sobre los MISMOS bytes.
const expected = 'sha256=' + crypto.createHmac('sha256', SECRET).update(buf).digest('hex');

// 4) Comparacion timing-safe (requiere igual longitud).
let firmaOk = false;
try {
  const a = Buffer.from(sigHeader);
  const b = Buffer.from(expected);
  firmaOk = a.length === b.length && crypto.timingSafeEqual(a, b);
} catch (e) {
  firmaOk = false;
}
if (!firmaOk) {
  return [{ json: { ok_firma: false, motivo: 'firma_invalida', ambiente_esperado: null, rol: null, action: null, ts: null } }];
}

// 5) Parseo (firma ya validada sobre bytes crudos).
let body;
try {
  body = JSON.parse(buf.toString('utf8'));
} catch (e) {
  return [{ json: { ok_firma: false, motivo: 'payload_invalido', ambiente_esperado: null, rol: null, action: null, ts: null } }];
}

// 6) Ventana de ts (anti-replay liviano, D-C-29): |now - ts| <= 300s.
const ts = Number(body.ts);
if (!Number.isFinite(ts) || Math.abs(Date.now() - ts) > 300000) {
  return [{ json: { ok_firma: false, motivo: 'ts_fuera_de_ventana', ambiente_esperado: body.ambiente_esperado ?? null, rol: body.rol ?? null, action: body.action ?? null, ts: body.ts ?? null } }];
}

// Allowlist de rol del wrapper (D-C-39, segunda defensa). A03 = jenny/vicky/socio.
const ROLES_OK = ['jenny', 'vicky', 'socio'];
if (!ROLES_OK.includes(body.rol)) {
  return [{ json: { ok_firma: false, motivo: 'rol_no_permitido', ambiente_esperado: body.ambiente_esperado ?? null, rol: body.rol ?? null, action: body.action ?? null, ts } }];
}

// Action binding (D-C-39 ext.): el endpoint solo acepta su accion esperada, aunque el sobre
// este bien firmado (evita ruteos cruzados). EXPECTED_ACTION = calendario.limpieza (A03).
const EXPECTED_ACTION = 'calendario.limpieza';
if (body.action !== EXPECTED_ACTION) {
  return [{ json: { ok_firma: false, motivo: 'accion_desconocida', ambiente_esperado: body.ambiente_esperado ?? null, rol: body.rol ?? null, action: body.action ?? null, ts } }];
}

return [{ json: { ok_firma: true, motivo: null, ambiente_esperado: body.ambiente_esperado ?? null, rol: body.rol ?? null, action: body.action ?? null, ts } }];

// Slice 0 / Fase C - compara ambiente y arma el envelope uniforme (D-C-18/35).
const v = $('validar_firma_ts_rol').first().json;
const ambItem = $('leer_ambiente').first();
const real = (ambItem && ambItem.json) ? (ambItem.json.valor ?? null) : null;

function envErr(code, message, detail) {
  return [{ json: { ok: false, error: { code, message, detail: detail ?? null } } }];
}

if (!v.ok_firma) {
  const msgs = {
    firma_invalida: 'firma HMAC invalida o ausente',
    ts_fuera_de_ventana: 'timestamp fuera de la ventana permitida (300s)',
    payload_invalido: 'cuerpo no es JSON valido',
    raw_body_ausente: 'no llego el raw body (activa Raw Body en el Webhook)',
    rol_no_permitido: 'rol no habilitado para esta accion',
    accion_desconocida: 'accion no corresponde a este endpoint'
  };
  return envErr(v.motivo, msgs[v.motivo] || 'rechazado', null);
}

if (v.ambiente_esperado !== real) {
  return envErr('ambiente_incorrecto', 'el sobre no corresponde a este entorno', { esperado: v.ambiente_esperado, real });
}

// Paso OK: marcador para que el IF habilite los reads. El envelope final lo arma el render.
return [{ json: { ok: true } }];

// ===== vita_w8c_html_limpieza__TEST — nodo Code (render) — v2 (camino 2) =====
// Solo lectura. Limpieza (Jennifer): 7 días, SIN montos. Motor del operativo filtrado
// + cruce con vista_limpieza_semana para mascotas/notas.
// Paleta: rojo > gris > amarillo (salida) > verde (entrada/ocupado) > blanco.

const TZ = 'America/Argentina/Buenos_Aires';
const DIAS_VENTANA = 7;

function esc(v) {
  if (v === null || v === undefined) return '';
  return String(v)
    .replace(/&/g, '&amp;').replace(/</g, '&lt;').replace(/>/g, '&gt;')
    .replace(/"/g, '&quot;').replace(/'/g, '&#39;');
}
function hhmm(t) { if (!t) return ''; const s = String(t); return s.length >= 5 ? s.slice(0, 5) : s; }
function primerNombre(full) { if (!full) return ''; return String(full).trim().split(/\s+/)[0]; }
// Normaliza cualquier fecha (date o timestamp '2026-06-01T00:00:00.000Z') a 'YYYY-MM-DD'
function ymd(v) { if (v === null || v === undefined) return ''; return String(v).slice(0, 10); }

function safeAll(nodeName, keyField) {
  try {
    const items = $(nodeName).all();
    const failed = items.some(it => it && it.json && (it.json.error || it.error));
    if (failed) return { ok: false, rows: [] };
    const rows = items.map(it => it.json).filter(j => j && j[keyField] !== undefined && j[keyField] !== null);
    return { ok: true, rows };
  } catch (e) { return { ok: false, rows: [] }; }
}

const gridR = safeAll('PG: leer grilla', 'id_cabana');     // vista_disponibilidad (7 dias)
const resR  = safeAll('PG: leer detalle', 'id_reserva');   // vista_calendario (SIN montos seleccionados)
const blkR  = safeAll('PG: leer bloqueos', 'id_bloqueo');  // bloqueos
const outR  = safeAll('PG: leer salidas', 'id_reserva');   // salidas (incluye completada)
const limpR = safeAll('PG: leer limpieza', 'id_cabana');   // vista_limpieza_semana (mascotas/notas)
const huboError = !gridR.ok || !resR.ok || !blkR.ok || !outR.ok || !limpR.ok;

if (huboError) {
  const htmlError = '<!DOCTYPE html><html lang="es"><head><meta charset="utf-8">'
    + '<meta name="viewport" content="width=device-width, initial-scale=1">'
    + '<title>Calendario de limpieza — Vita Delta</title>'
    + '<style>body{font-family:system-ui,Arial,sans-serif;background:#f5f5f5;margin:0;padding:2rem;color:#333}'
    + '.box{max-width:480px;margin:3rem auto;background:#fff;border-radius:12px;padding:2rem;text-align:center;box-shadow:0 1px 4px rgba(0,0,0,.1)}'
    + 'h1{font-size:1.2rem;margin:0 0 .5rem}p{color:#666;line-height:1.5}</style></head>'
    + '<body><div class="box"><h1>No se pudo cargar el calendario</h1>'
    + '<p>Hubo un problema temporal al obtener los datos. Reintentá en unos minutos.</p>'
    + '<p>Si el problema persiste, avisá al equipo.</p></div></body></html>';
  return [{ json: { ok: false, error: { code: 'error_interno', message: 'no se pudo cargar el calendario', detail: null } } }];
}

const ORDEN_CABANAS = [
  { id: 1, nombre: 'Bamboo' }, { id: 2, nombre: 'Madre Selva' }, { id: 3, nombre: 'Arrebol' },
  { id: 4, nombre: 'Guatemala' }, { id: 5, nombre: 'Tokio' },
];

const dias = Array.from(new Set(gridR.rows.map(r => ymd(r.fecha)))).sort();
const primerDiaVisible = dias.length ? dias[0] : null;

const reservasPorCabana = {};
for (const r of resR.rows) (reservasPorCabana[r.id_cabana] = reservasPorCabana[r.id_cabana] || []).push(r);

const salidasPorCabana = {};
const vistosSalida = new Set();
function pushSalida(idc, idr, fecha, hora, nombre) {
  const k = String(idr);
  if (vistosSalida.has(k)) return;
  vistosSalida.add(k);
  (salidasPorCabana[idc] = salidasPorCabana[idc] || []).push({ id_reserva: idr, fecha_checkout: fecha, hora_checkout: hora, huesped_nombre: nombre });
}
for (const r of resR.rows) pushSalida(r.id_cabana, r.id_reserva, ymd(r.fecha_checkout), r.hora_checkout, r.huesped_nombre);
for (const s of outR.rows) pushSalida(s.id_cabana, s.id_reserva, ymd(s.fecha_checkout), s.hora_checkout, s.huesped_nombre);

const bloqueosEspecificos = {};
const bloqueosTotales = [];
for (const b of blkR.rows) {
  if (b.id_cabana === null || b.id_cabana === undefined) bloqueosTotales.push(b);
  else (bloqueosEspecificos[b.id_cabana] = bloqueosEspecificos[b.id_cabana] || []).push(b);
}

// Cruce de limpieza: mascotas/notas por cabana|fecha|tipo (solo del checkin entrante)
const extraEntrada = {}; // "idc|fecha" -> { mascotas, detalle, notas, personas, telefono }
for (const m of limpR.rows) {
  if (m.tipo_movimiento === 'checkin') {
    extraEntrada[m.id_cabana + '|' + ymd(m.fecha_movimiento)] = {
      mascotas: m.mascotas, detalle: m.detalle_mascotas, notas: m.notas_reserva,
      personas: m.personas, telefono: m.huesped_telefono
    };
  }
}

function reservasDeCabana(idc) { return reservasPorCabana[idc] || []; }
function salidasDeCabana(idc) { return salidasPorCabana[idc] || []; }
function entradaEseDia(idc, dia) { return reservasDeCabana(idc).find(r => ymd(r.fecha_checkin) === dia) || null; }
function salidaEseDia(idc, dia) { return salidasDeCabana(idc).find(s => ymd(s.fecha_checkout) === dia) || null; }
function ocupadaEseDia(idc, dia) {
  return reservasDeCabana(idc).find(r =>
    (ymd(r.fecha_checkin) <= dia && dia < ymd(r.fecha_checkout)) || ymd(r.fecha_checkout) === dia) || null;
}
function bloqueosQueCubren(idc, dia) {
  const esp = (bloqueosEspecificos[idc] || []).filter(b => ymd(b.fecha_desde) <= dia && dia < ymd(b.fecha_hasta));
  const tot = bloqueosTotales.filter(b => ymd(b.fecha_desde) <= dia && dia < ymd(b.fecha_hasta));
  return esp.concat(tot);
}

function calcularCelda(idc, dia) {
  const entra = entradaEseDia(idc, dia);
  const sale = salidaEseDia(idc, dia);
  const ocupa = ocupadaEseDia(idc, dia);
  const bloqueosCubren = bloqueosQueCubren(idc, dia);
  const bloqueado = bloqueosCubren.length > 0;
  // PRIORIDAD limpieza: rojo > gris > amarillo(salida) > verde(entrada/ocupado) > blanco
  if (entra && sale && entra.id_reserva !== sale.id_reserva) return { color: 'rojo', entra, sale };
  if (bloqueado) return { color: 'gris', bloqueosCubren };
  if (sale && !entra) return { color: 'amarillo', sale };
  if (entra) return { color: 'verde', tipo: 'entrada', reserva: entra };
  if (ocupa) return { color: 'verde', tipo: 'intermedio', reserva: ocupa, esInicio: ymd(ocupa.fecha_checkin) === dia || (primerDiaVisible === dia) };
  return { color: 'blanco' };
}

const COLORES = {
  rojo:     { bg: '#f8d2d2', label: 'Salida + entrada (atención)' },
  gris:     { bg: '#d9d9d9', label: 'Bloqueo' },
  amarillo: { bg: '#fdf0c2', label: 'Salida (limpiar)' },
  verde:    { bg: '#cdeccd', label: 'Entrada / ocupado' },
  blanco:   { bg: '#ffffff', label: 'Sin movimiento' },
};

function masNotas(idc, dia) {
  const e = extraEntrada[idc + '|' + dia];
  if (!e) return '';
  const masc = e.mascotas ? ('🐾 ' + (e.detalle ? esc(e.detalle) : 'sí')) : '';
  const nota = e.notas ? ('📝 ' + esc(e.notas)) : '';
  return [masc, nota].filter(Boolean).join(' · ');
}

function contenidoCelda(idc, dia) {
  const c = calcularCelda(idc, dia);
  const bg = COLORES[c.color].bg;
  let f1 = '', f2 = '', f3 = '';
  if (c.color === 'rojo') {
    f1 = 'Sale ' + esc(primerNombre(c.sale.huesped_nombre)) + ' · ' + hhmm(c.sale.hora_checkout) + '<br>'
       + 'Entra ' + esc(c.entra.huesped_nombre) + ' · ' + esc(c.entra.personas) + 'p · ' + hhmm(c.entra.hora_checkin);
    f2 = esc(c.entra.huesped_telefono);
    f3 = masNotas(idc, dia);
  } else if (c.color === 'amarillo') {
    f1 = 'Sale ' + esc(primerNombre(c.sale.huesped_nombre)) + ' · ' + hhmm(c.sale.hora_checkout);
  } else if (c.color === 'verde' && c.tipo === 'entrada') {
    f1 = 'Entra ' + esc(c.reserva.huesped_nombre) + ' · ' + esc(c.reserva.personas) + 'p · ' + hhmm(c.reserva.hora_checkin);
    f2 = esc(c.reserva.huesped_telefono);
    f3 = masNotas(idc, dia);
  } else if (c.color === 'verde' && c.tipo === 'intermedio') {
    // día ocupado sin movimiento: verde, sin texto (no hay tarea de limpieza)
  } else if (c.color === 'gris') {
    const b = c.bloqueosCubren[0];
    const extra = c.bloqueosCubren.length > 1 ? ' (+)' : '';
    f1 = esc(b ? b.motivo : 'bloqueo') + extra;
  }
  return { bg, f1, f2, f3 };
}

const DIA_SEMANA = ['Dom','Lun','Mar','Mié','Jue','Vie','Sáb'];
function etiquetaDia(f) {
  const s = ymd(f);
  const parts = s.split('-');
  if (parts.length !== 3) return s;
  const d = new Date(Date.UTC(+parts[0], +parts[1]-1, +parts[2]));
  return DIA_SEMANA[d.getUTCDay()] + ' ' + parts[2] + '/' + parts[1];
}

let thDias = '<th class="cab">Cabaña</th>';
for (const d of dias) thDias += '<th class="dia">' + etiquetaDia(d) + '</th>';
let cuerpo = '';
for (const cab of ORDEN_CABANAS) {
  const celdas = dias.map(d => contenidoCelda(cab.id, d));
  let tr1 = '<td class="cab" rowspan="3">' + esc(cab.nombre) + '</td>';
  let tr2 = '', tr3 = '';
  celdas.forEach(cel => {
    tr1 += '<td class="cell f1" style="background:' + cel.bg + '">' + cel.f1 + '</td>';
    tr2 += '<td class="cell f2" style="background:' + cel.bg + '">' + cel.f2 + '</td>';
    tr3 += '<td class="cell f3" style="background:' + cel.bg + '">' + cel.f3 + '</td>';
  });
  cuerpo += '<tr class="r-mov">' + tr1 + '</tr><tr class="r-tel">' + tr2 + '</tr><tr class="r-extra">' + tr3 + '</tr>';
}

const ahora = new Intl.DateTimeFormat('es-AR', { timeZone: TZ, dateStyle: 'short', timeStyle: 'short' }).format(new Date());
const leyenda = Object.values(COLORES).map(c => '<span class="lg"><span class="sw" style="background:' + c.bg + '"></span>' + c.label + '</span>').join('');

const html = '<!DOCTYPE html><html lang="es"><head><meta charset="utf-8">'
  + '<meta name="viewport" content="width=device-width, initial-scale=1">'
  + '<title>Calendario de limpieza — Vita Delta</title>'
  + '<style>'
  + 'body{font-family:system-ui,Arial,sans-serif;margin:0;padding:1rem;background:#fafafa;color:#222}'
  + 'h1{font-size:1.3rem;margin:.2rem 0}'
  + '.info{color:#666;font-size:.8rem;margin-bottom:.8rem}'
  + '.leyenda{margin:.5rem 0 1rem;font-size:.8rem}'
  + '.lg{margin-right:1rem;white-space:nowrap}.sw{display:inline-block;width:14px;height:14px;border:1px solid #aaa;vertical-align:middle;margin-right:4px}'
  + '.scroll{overflow-x:auto;border:1px solid #ddd;border-radius:8px}'
  + 'table{border-collapse:collapse;font-size:.72rem;min-width:100%}'
  + 'th,td{border:1px solid #e0e0e0;padding:3px 5px;text-align:center;vertical-align:middle}'
  + 'th.dia{min-width:120px}'
  + 'td.cab,th.cab{position:sticky;left:0;background:#f0f0f0;font-weight:bold;text-align:left;min-width:90px;z-index:1}'
  + '.cell{min-width:120px;font-size:.68rem;line-height:1.2;height:20px}'
  + '.r-mov .f1{font-weight:bold}'
  + '</style></head>'
  + '<body>'
  + '<h1>Calendario de limpieza — Complejo Vita Delta</h1>'
  + '<div class="info">Datos al ' + esc(ahora) + ' · próximos 7 días · TEST</div>'
  + '<div class="leyenda">' + leyenda + '</div>'
  + '<div class="scroll"><table><thead><tr>' + thDias + '</tr></thead><tbody>' + cuerpo + '</tbody></table></div>'
  + '</body></html>';

return [{ json: { ok: true, data: { formato: 'html', html } } }];
